const callbackData = $input.first().json.callback_query.data;
const chatId = $input.first().json.callback_query.message.chat.id;
const messageId = $input.first().json.callback_query.message.message_id;
const callbackQueryId = $input.first().json.callback_query.id;

// Check if it's a task view request
if (callbackData.startsWith('view_')) {
  const taskId = callbackData.replace('view_', '');

  return [{
    json: {
      action: 'view_task',
      taskId: taskId,
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

// Check if it's a status update request
if (callbackData.startsWith('update_')) {
  const parts = callbackData.split('_');
  const taskId = parts[1];
  const newStatus = parts.slice(2).join('_');

  return [{
    json: {
      action: 'update_status',
      taskId: taskId,
      newStatus: newStatus,
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

// Handle refresh
if (callbackData === 'refresh_tasks') {
  return [{
    json: {
      action: 'refresh_task',
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

// Handle To do
if (callbackData === 'To do') {
  return [{
    json: {
      action: 'To do',
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

// Handle In progress
if (callbackData === 'In progress') {
  return [{
    json: {
      action: 'In progress',
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

// Handle Done
if (callbackData === 'Done') {
  return [{
    json: {
      action: 'Done',
      chatId: chatId,
      messageId: messageId,
      callbackQueryId: callbackQueryId
    }
  }];
}

//Default
return [{
  json: {
    action: 'unknown',
    chatId: chatId,
    messageId: messageId
  }
}];

const task = $input.first().json;
const chatId = $('Extract Button').item.json.chatId;
const messageId = $('Extract Button').item.json.messageId;
const callbackQueryId = $('Extract Button').item.json.callbackQueryId;

// Helper function
function getPriorityEmoji(priority) {
  const map = { 
    'High': '🔴', 
    'Medium': '🟡', 
    'Low': '🟢' 
  };
  return map[priority] || '⚪';
}

function getStatusEmoji(status) {
  const map = {
    'To do': '📝',
    'In progress': '🔄',
    'Done': '✅'
  };
  return map[status] || '📊';
}

// Build detailed card
const priority = getPriorityEmoji(task.property_priority);
const statusEmoji = getStatusEmoji(task.property_status);

let message = "📋 *TASK DETAILS* ";

message += `*${task.property_name}*\n`;

message += `📅 *Start Date*\n`;
message += `   ${task.property_due_date?.start || 'Not set'}\n\n`;

message += `🏁 *End Date*\n`;
message += `   ${task.property_due_date?.end || 'Not set'}\n\n`;

message += `${priority} *Priority*\n`;
message += `   ${task.property_priority}\n\n`;

message += `${statusEmoji} *Status*\n`;
message += `   ${task.property_status}\n\n`;

message += `📁 *Category*\n`;
message += `   ${task.property_category}\n\n`;

if (task.property_days_left !== null && task.property_days_left !== undefined) {
  const daysLeftText = task.property_days_left === 0 ? 'Due today!' : 
                       task.property_days_left > 0 ? `${task.property_days_left} days left` :
                       `${Math.abs(task.property_days_left)} days overdue`;
  message += `⏰ *Time Remaining*\n`;
  message += `   ${daysLeftText}\n\n`;
}


// Create action buttons based on current status
const buttons = [];

if (task.property_status === 'To do') {
  buttons.push([
    {
      text: "▶️ Start Task",
      callback_data: `update_${task.id}_In progress`
    }
  ]);
} else if (task.property_status === 'In progress') {
  buttons.push([
    {
      text: "✅ Complete",
      callback_data: `update_${task.id}_Done`
    }
  ]);
} 

// Add back button
buttons.push([{
  text: "⬅️ Back to List",
  callback_data: "refresh_tasks"
}]);

// Create payload for editing message
const telegramPayload = {
  chat_id: chatId,
  message_id: messageId,
  text: message,
  parse_mode: "Markdown",
  reply_markup: {
    inline_keyboard: buttons
  }
};

return [{
  json: {
    telegramPayload: telegramPayload,
    callbackQueryId: callbackQueryId
  }
}];

const items = $input.all();
const chatId = $('Switch').item.json.chatId;

// Count tasks by status
const todoCount = items.filter(item => item.json.property_status === 'To do').length;
const inProgressCount = items.filter(item => item.json.property_status === 'In progress').length;
const doneCount = items.filter(item => item.json.property_status === 'Done').length;

// Build message
let message = "📋 *Task Manager*\n\n";
message += `📊 *Overview:*\n`;
message += `• To Do: ${todoCount} tasks\n`;
message += `• In Progress: ${inProgressCount} tasks\n`;
message += `• Done: ${doneCount} tasks\n`;
message += `• Total: ${items.length} tasks\n\n`;
message += `👇 *Choose a status to view tasks*`;

// Create status filter buttons
const buttons = [
  [
    {
      text: `📝 To Do (${todoCount})`,
      callback_data: "To do"
    }
  ],
  [
    {
      text: `🔄 In Progress (${inProgressCount})`,
      callback_data: "In progress"
    }
  ],
  [
    {
      text: `✅ Done (${doneCount})`,
      callback_data: "Done"
    }
  ],
  [
    {
      text: "🔄 Refresh",
      callback_data: "refresh_tasks"
    }
  ]
];

// Create Telegram API payload
const telegramPayload = {
  chat_id: chatId,
  text: message,
  parse_mode: "Markdown",
  reply_markup: {
    inline_keyboard: buttons
  }
};

return [{
  json: {
    telegramPayload: telegramPayload
  }
}];

const telegramMessage = $input.first().json.action;
const notionStatusFilter = {

    "property": "Status",
    "status": {
      "equals": telegramMessage

  }

}

return [
  { 
    json: {  // ← Changed to lowercase "json"
      telegramMessage: telegramMessage,
      userId: $input.first().json.chatId,
      filterNotion : JSON.stringify(notionStatusFilter)
    }
  }
];

const items = $input.all();
const chatId = $('Telegram Trigger').first().json.callback_query.message.chat.id;
// Separate tasks by status
const todoTasks = items.filter(item => item.json.property_status === 'To do');
const inProgressTasks = items.filter(item => item.json.property_status === 'In progress');
const doneTasks = items.filter(item => item.json.property_status === 'Done');

// Helper function for priority emojis
function getPriorityEmoji(priority) {
  const map = { 
    'High': '🔴', 
    'Medium': '🟡', 
    'Low': '🟢' 
  };
  return map[priority] || '⚪';
}

// Build simple message
let message = "📋 *Your Tasks*\n\n";
message += `📊 Overview:\n`;
message += `• To Do: ${todoTasks.length}\n`;
message += `• In Progress: ${inProgressTasks.length}\n`;
message += `• Done: ${doneTasks.length}\n`;
message += `• Total: ${items.length}\n\n`;
message += `👇 *Select a task to view details*`;

// Create buttons array
const buttons = [];

// TO DO Section Buttons
if (todoTasks.length > 0) {
  todoTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} 📝 ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}

// IN PROGRESS Section Buttons
if (inProgressTasks.length > 0) {
  inProgressTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} 🔄 ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}

// DONE Section Buttons
if (doneTasks.length > 0) {
  doneTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} ✅ ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}


// Create Telegram API payload
const telegramPayload = {
  chat_id: chatId,
  text: message,
  parse_mode: "Markdown",
  reply_markup: {
    inline_keyboard: buttons
  }
};

return [{
  json: {
    telegramPayload: telegramPayload
  }
}];

const updatedTask = $input.first().json;
const extractedData = $('Update Page').first().json;
const chatId = $('Extract Button').item.json.chatId;
const messageId = $('Extract Button').item.json.messageId;
const newStatus = extractedData.property_status;

// Get task name from the updated Notion response
const taskName = updatedTask.property_name || 'Task';

// Helper function for status emojis
function getStatusEmoji(status) {
  const map = {
    'To do': '📝',
    'In progress': '🔄',
    'Done': '✅'
  };
  return map[status] || '📊';
}

const emoji = getStatusEmoji(newStatus);

// Build confirmation message
let message = "✅ *Status Updated!*\n\n";
message += `${emoji} *${taskName}*\n\n`;
message += `New status: *${newStatus}*\n\n`;

// Add motivational message based on status
if (newStatus === 'In progress') {
  message += `🚀 Great! You've started working on this task.\n\n`;
} else if (newStatus === 'Done') {
  message += `🎉 Awesome! Task completed!\n\n`;
} else if (newStatus === 'To do') {
  message += `📝 Task moved back to To Do.\n\n`;
}

message += `What would you like to do next?`;

// Create navigation buttons
const buttons = [
  [
    {
      text: "⬅️ Back to Menu",
      callback_data: "refresh_tasks"
    }
  ]
];

// Create Telegram payload
const telegramPayload = {
  chat_id: chatId,
  message_id: messageId,
  text: message,
  parse_mode: "Markdown",
  reply_markup: {
    inline_keyboard: buttons
  }
};

return [{
  json: {
    telegramPayload: telegramPayload
  }
}];
